import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ThemeProvider } from "./context/ThemeContext";
importNavba

function App() {
    return (
        <Navbar>
            <ThemeProvider>
                <Router>
                    <Routes>
                        <Route />
                    </Routes>
                </Router>
            </ThemeProvider>
        </Navbar>
    );
}
